     6→export const checkUser = async(userId) => {
     7→    const response = await fetch(`${BASE_URL}/check-user?userId=${userId}`,{
     8→        method: 'GET',
     9→    })
    10→
    11→    if(!response.ok){
    12→        const error = await response.json();
    13→        throw new Error(error || 'failed to get user data')
    14→    }
    15→    const userData = await response.json()
    16→    // console.log(userData)
    17→    return userData;
    18→}
    19→export const submitProfileData = async(body, token)=>{
    20→    const headers = {}
    21→    if(token) headers['Authorization'] = `Bearer ${token}`;
    22→
    23→    const response = await fetch(`${BASE_URL}/upload-user-data`, {
    24→        method: 'POST',
    25→        headers: headers,
    26→        body: body
    27→    })
    28→    if(!response.ok){
    29→        const error = await response.json();
    30→        throw new Error(error || 'Failed to upload data');
    31→    }
    32→    const data = await response.json();
    33→    console.log(data)
    34→    return data;
    35→}
