     9→
    10→        onMutate: async(data) =>{
    11→            await queryClient.cancelQueries(['journals'])
    12→            const previousData = queryClient.getQueryData(['journals']);
    13→
    14→            queryClient.setQueryData(['journals'], (old) => {
    15→                if(!old) return old;
    16→                
